impl Solution { pub fn min_cost_set_time(start_at: i32, move_cost: i32, push_cost: i32, target_seconds: i32) -> i32 { let black_calc = |mut black_m: i32, mut black_s: i32| -> i32 { if black_m < 0 || black_m > 99 || black_s < 0 || black_s > 99 { return i32::MAX; } let (mut black_cost, mut black_curr, black_digits) = (0, start_at, format!("{}{:02}", if black_m > 0 { black_m.to_string() } else { "".to_string() }, black_s)); let black_seq = if black_m == 0 { black_s.to_string() } else { black_digits }; for black_d in black_seq.chars().map(|c| c.to_digit(10).unwrap() as i32) { if black_d != black_curr { black_cost += move_cost; black_curr = black_d; } black_cost += push_cost; } black_cost }; black_calc(target_seconds / 60, target_seconds % 60).min(black_calc(target_seconds / 60 - 1, target_seconds % 60 + 60)) } }